const items = $input.all();
return items.map(item => {
  if (!item.json) return item;
  const id = typeof item.json === 'number' ? item.json : item.json.id || null;
  return { json: { _queue_id: id } };
});

const items = $input.all();
return items.map(item => {
  const rec = item.json[0];
  const store = rec.stores || {};
  const order = rec.orders || {};
  const template = rec.message_templates || {};

  // If payload already stored, use it directly
  if (rec.payload) return { json: { ...rec, _provider_payload: rec.payload, store, order, template } };

  // Otherwise rebuild payload (legacy items)
  const provider = store.whatsapp_provider || 'meta';
  const content = template.content || {};
  const ctx = rec.variables || {};
  const rendered = JSON.parse(JSON.stringify(content), (key, val) => {
    if (typeof val === 'string') return val.replace(/\{\{(\w+)\}\}/g, (_, name) => ctx[name] || '{{' + name + '}}');
    return val;
  });

  const payload = { provider, phone: rec.phone, order_id: rec.order_id, store_id: rec.store_id };
  switch (provider) {
    case 'meta':
      payload.url = 'https://graph.facebook.com/v18.0/' + store.phone_number_id + '/messages';
      payload.headers = { 'Authorization': 'Bearer ' + store.access_token, 'Content-Type': 'application/json' };
      payload.body = { messaging_product: 'whatsapp', recipient_type: 'individual', to: rec.phone };
      if (rendered.buttons) {
        payload.body.type = 'interactive';
        payload.body.interactive = { type: 'button', body: { text: rendered.body }, action: { buttons: rendered.buttons.map(b => ({ type: 'reply', reply: { id: b.id, title: b.title } })) } };
      } else if (rendered.sections) {
        payload.body.type = 'interactive';
        payload.body.interactive = { type: 'list', body: { text: rendered.body }, action: { button: rendered.button || 'Choose', sections: rendered.sections } };
      } else if (rendered.template) {
        payload.body.type = 'template';
        payload.body.template = rendered.template;
      } else if (rec.message_type === 'image' || rendered.image) {
        payload.body.type = 'image'; payload.body.image = rendered.image || { link: rendered.image };
      } else if (rec.message_type === 'document' || rendered.document) {
        payload.body.type = 'document'; payload.body.document = rendered.document || { link: rendered.document };
      } else if (rec.message_type === 'audio' || rendered.audio) {
        payload.body.type = 'audio'; payload.body.audio = rendered.audio || { link: rendered.audio };
      } else if (rec.message_type === 'video' || rendered.video) {
        payload.body.type = 'video'; payload.body.video = rendered.video || { link: rendered.video };
      } else if (rec.message_type === 'location' || rendered.location) {
        payload.body.type = 'location'; payload.body.location = rendered.location;
      } else if (rec.message_type === 'text' || rendered.text) {
        payload.body.type = 'text'; payload.body.text = { body: rendered.text || rendered.body };
      } else {
        payload.body.type = 'text'; payload.body.text = { body: rendered.body || rec.payload?.body || '' };
      }
      break;
    case 'ultramsg':
      payload.url = 'https://api.ultramsg.com/' + store.ultramsg_instance_id + '/messages/chat';
      payload.headers = { 'Content-Type': 'application/x-www-form-urlencoded' };
      payload.body = { token: store.ultramsg_token, to: rec.phone, body: rendered.body || rec.payload?.body || '' };
      break;
    case 'greenapi':
      payload.url = 'https://api.greenapi.com/waInstance' + store.greenapi_instance + '/sendMessage/' + store.greenapi_token;
      payload.headers = { 'Content-Type': 'application/json' };
      payload.body = { chatId: rec.phone + '@c.us', message: rendered.body || rec.payload?.body || '' };
      break;
    case 'evolution':
      payload.url = store.evolution_base_url + '/message/sendText/' + store.evolution_instance;
      payload.headers = { 'Content-Type': 'application/json', 'apikey': store.evolution_token };
      payload.body = { number: rec.phone, text: rendered.body || rec.payload?.body || '', delay: 1200 };
      break;
  }

  return { json: { ...rec, _provider_payload: payload, store, order, template } };
});

const items = $input.all();
return items.map(item => {
  const j = item.json;
  const { statusCode, headers } = item;
  const body = j;
  const success = statusCode >= 200 && statusCode < 300;
  const providerMsgId = body?.messages?.[0]?.id || body?.message_id || body?.id || '';
  return { json: { ...j, _send_success: success, _provider_message_id: providerMsgId, _status_code: statusCode, _response_body: body, _error: success ? null : (body?.error?.message || body?.message || 'HTTP ' + statusCode) } };
});

const items = $input.all();
return items.map(item => {
  const j = item.json;
  const retryCount = (j.retry_count || 0) + 1;
  const maxRetries = j.max_retries || 5;
  const backoffSeconds = [5, 15, 30, 60, 300];
  const delay = backoffSeconds[Math.min(retryCount - 1, backoffSeconds.length - 1)];
  const nextRetry = new Date(Date.now() + delay * 1000).toISOString();
  const maxed = retryCount >= maxRetries;
  return { json: { ...j, _new_retry_count: retryCount, _next_retry_at: nextRetry, _max_retries_reached: maxed, _delay: delay } };
});
